					const R = j === cpuN - 1 ? -vx[idx] : vx[ni(i, j, 0, 1)];
					const T = i === 0 ? -vy[idx] : vy[ni(i, j, -1, 0)];
					const B = i === cpuN - 1 ? -vy[idx] : vy[ni(i, j, 1, 0)];
					divg[idx] = .5 * (R - L + B - T);
