					const idx = i * cpuN + j;
					vtx[idx] = bl(vx, j - vx[idx] * dt, i - vy[idx] * dt) / vDecay;
					vty[idx] = bl(vy, j - vx[idx] * dt, i - vy[idx] * dt) / vDecay;
